/* 三层驱动架构接口定义 */

/* === Layer 1: LL (Low Layer) === */
/* 直接操作寄存器，零抽象开销 */
static inline void ll_uart_send_byte(USART_TypeDef *uart,
                                     uint8_t byte) {
    uart->DR = byte;                    /* 写入数据寄存器 */
    while (!(uart->SR & USART_SR_TXE));/* 等待发送完成 */
}

static inline uint8_t ll_uart_recv_byte(USART_TypeDef *uart) {
    while (!(uart->SR & USART_SR_RXNE));/* 等待接收就绪 */
    return (uint8_t)uart->DR;           /* 读取数据寄存器 */
}

/* === Layer 2: HAL (Abstraction) === */
/* 封装同步、超时、错误码 */
typedef struct {
    USART_TypeDef *instance;            /* 硬件实例指针 */
    uint32_t timeout_ms;                /* 默认超时时间 */
} uart_hal_t;

int hal_uart_transmit(uart_hal_t *u,
                      const uint8_t *data,
                      uint16_t len) {
    if (!u || !data || len == 0)
        return -1;                      /* 参数校验 */
    for (uint16_t i = 0; i < len; i++) {
        ll_uart_send_byte(u->instance,
                          data[i]);     /* 调用 LL 层 */
    }
    return 0;                           /* 成功 */
}

/* === Layer 3: Application Driver === */
/* 面向业务逻辑的简洁接口 */
void app_uart_send_log(const char *msg) {
    static uart_hal_t log_uart = {
        .instance = USART1,
        .timeout_ms = 100
    };
    hal_uart_transmit(&log_uart,
                      (const uint8_t*)msg,
                      strlen(msg));
}

/* uart_hal.c — UART HAL 层实现 */
#include "uart_hal.h"
#include <string.h>

/* 获取系统当前 tick（需由用户实现）*/
extern uint32_t get_tick_ms(void);

/* LL 层原语（由 ll_uart.c 提供）*/
extern void ll_uart_send_byte(USART_TypeDef *uart,
                              uint8_t byte);
extern uint8_t ll_uart_recv_byte(USART_TypeDef *uart);

/* 发送缓冲区数据，带超时保护 */
int uart_hal_transmit(uart_hal_t *hal,
                      const uint8_t *buf,
                      uint16_t len) {
    if (!hal || !buf || len == 0)
        return ERR_PARAM;              /* -1: 参数无效 */

    uint32_t start = get_tick_ms();     /* 记录起始时间 */
    for (uint16_t i = 0; i < len; i++) {
        ll_uart_send_byte(hal->uart,
                          buf[i]);      /* 逐字节发送 */
        /* 超时检查：每发一个字节都检查 */
        if ((get_tick_ms() - start) >
            hal->timeout_ms) {
            return ERR_TIMEOUT;         /* -2: 传输超时 */
        }
    }
    return 0;                           /* 全部发送成功 */
}

/* 接收单个字节，带超时 */
int uart_hal_receive(uart_hal_t *hal,
                     uint8_t *out,
                     uint32_t timeout_ms) {
    if (!hal || !out)
        return ERR_PARAM;

    uint32_t start = get_tick_ms();
    while ((get_tick_ms() - start) < timeout_ms) {
        if (hal->uart->SR & USART_SR_RXNE) {
            *out = ll_uart_recv_byte(
                hal->uart);             /* 读取接收数据 */
            return 0;                   /* 成功 */
        }
    }
    return ERR_TIMEOUT;                 /* -2: 接收超时 */
}

/* 陷阱四演示：错误的循环依赖 */

/* ll_gpio.c — LL 层不应该依赖 HAL 层 */
#include "stm32f4xx_ll_gpio.h"
#include "stm32f4xx_hal.h"          /* ❌ LL 层引入 HAL */

void ll_gpio_delay_ms(uint32_t ms) {
    HAL_Delay(ms);                  /* ❌ LL 依赖 HAL！ */
}

/* 正确做法：LL 层使用纯软件延时 */
void ll_gpio_delay_ms_fixed(uint32_t ms) {
    for (; ms > 0; ms--) {
        for (volatile int i = 0; i < 800; i++) {
            __ASM("nop");           /* 约 1ms @ 168MHz */
        }
    }
}

/* 陷阱三演示：正确的 NVIC 优先级设置 */
void uart_dma_init(void) {
    /* DMA 中断优先级必须高于 GPIO 中断 */
    NVIC_SetPriority(DMA1_Channel4_IRQn, 0);
    NVIC_SetPriority(EXTI0_IRQn, 5);
    NVIC_EnableIRQ(DMA1_Channel4_IRQn);
    NVIC_EnableIRQ(EXTI0_IRQn);
}

