/* ll_gpio.c — LL 层：直接寄存器操作 */
static inline void ll_gpio_set(GPIO_TypeDef *g,
                               uint16_t pin) {
    g->BSRR = pin;                    /* 置位寄存器 */
}
static inline void ll_gpio_clear(GPIO_TypeDef *g,
                                 uint16_t pin) {
    g->BSRR = (uint32_t)pin << 16U;   /* 复位寄存器 */
}

/* i2c_sensor.c — HAL 层：封装 I2C 读取 */
int sensor_read_temp(sensor_handle_t *s,
                     float *out_temp) {
    uint8_t reg = 0x07;
    uint8_t data[2];
    if (HAL_I2C_Mem_Read(s->hi2c,
             s->addr, reg, 1,
             data, 2, 100) != HAL_OK)
        return -1;
    int16_t raw = (data[0] << 8) | data[1];
    *out_temp = raw / 100.0f;
    return 0;
}

/* main.c — 应用层：只含业务逻辑 */
int main(void) {
    sensor_init(&sensor_ctx);
    ll_gpio_set(GPIOA, GPIO_PIN_5);
    while (1) {
        float temp;
        if (sensor_read_temp(&sensor_ctx,
                            &temp) == 0) {
            if (temp > 80.0f)
                ll_gpio_clear(GPIOA,
                            GPIO_PIN_5);
            else
                ll_gpio_set(GPIOA,
                            GPIO_PIN_5);
        }
    }
}
